const event = { timestamp: new Date().toISOString(), user_id: payload.user_id ?? 'unknown', workspace_id: payload.workspace_id ?? 'unknown', session_id: payload.session_id ?? null, tool_name: payload.tool_name ?? 'unknown', input_payload: payload.input_payload ?? {}, output_payload: payload.output_payload ?? {}, status: payload.status ?? 'success', error_message: payload.error_message ?? null, approval_required: Boolean(payload.approval_required), approved_by: payload.approved_by ?? null };
return [{ json: { status: 'success', event, note: 'Connect Postgres insert for durable audit logging in production.' } }];
